const input = $json;
const now = new Date().toISOString();
const draftId = input?.data?.p1_moc_nummer || `DRAFT-${Date.now()}`;
return [{
  ok: true,
  source: 'moc-save-draft',
  draftId,
  status: input.status || 'Draft',
  page: input.page || 1,
  requester: input.requester || null,
  storedAt: now,
  message: 'Concept opgeslagen in workflow.'
}];

const input = $json || {};
const data = input.data || {};
const submittedAt = input.submittedAt || new Date().toISOString();
const year = new Date(submittedAt).getFullYear();
const random = String(Math.floor(Math.random() * 9000) + 1000);
const mocId = data.p1_moc_nummer || `MOC-${year}-${random}`;

const routingRoles = input.routingRoles || {};
const mocTypes = Array.isArray(data.p2_type_moc)
  ? data.p2_type_moc
  : data.p2_type_moc
    ? [data.p2_type_moc]
    : [];

const baseAssignments = [
  { role: 'Aanvrager', assignee: routingRoles.aanvrager || 'Aanvrager' },
  { role: 'Technical Engineer / Hoofd TD', assignee: routingRoles.technicalEngineer || 'Technical Engineer / Hoofd TD' },
  { role: 'Directie / HR', assignee: routingRoles.directieHR || 'Directie / HR' },
  { role: 'Plantmanager / Directie', assignee: routingRoles.plantmanagerDirectie || 'Plantmanager / Directie' },
  { role: 'IT manager / directie', assignee: routingRoles.itManagerDirectie || 'IT manager / directie' }
];

const typeMapping = {
  Techniek: 'Technical Engineer / Hoofd TD',
  Personeel: 'Directie / HR',
  Organisatie: 'Plantmanager / Directie',
  IT: 'IT manager / directie'
};

const selectedByType = mocTypes.map((type) => ({
  mocType: type,
  teamRole: typeMapping[type] || 'Aanvrager'
}));

const uniqueAssignments = [];
const seen = new Set();
for (const entry of baseAssignments) {
  const key = `${entry.role}|${entry.assignee}`;
  if (!seen.has(key)) {
    seen.add(key);
    uniqueAssignments.push(entry);
  }
}

const aanvraagValide = Boolean(input.aanvraagValide);
const nextStatus = aanvraagValide ? 'Hazard_P4' : 'Rejected_No_Page3_Yes';

const executionDateRaw = input?.reminders?.basedOnExecutionDate || data.p3_datum_uitvoering || null;
let reminderDate = null;
if (executionDateRaw) {
  const baseDate = new Date(executionDateRaw);
  if (!Number.isNaN(baseDate.getTime())) {
    baseDate.setDate(baseDate.getDate() + 28);
    reminderDate = baseDate.toISOString().slice(0, 10);
  }
}

return [{
  ok: true,
  source: 'moc-submit-full',
  mocId,
  submittedAt,
  aanvraagValide,
  nextStatus,
  requiresHazardIdentification: Boolean(input.requiresHazardIdentification),
  mocTypes,
  selectedByType,
  teamAssignments: uniqueAssignments,
  reminder: {
    enabled: Boolean(reminderDate),
    dueDate: reminderDate,
    reminderEvent: input?.reminders?.reminderEvent || 'moc.evaluation.reminder.4weeks'
  },
  analytics: input.analytics || {},
  workflowNotes: [
    'Pagina 3 leidend: minimaal 1x Ja vereist voor valide aanvraag.',
    'Pagina 4 per functionaris invullen inclusief toelichting.',
    'Pagina 8 evaluatie 4 weken na uitvoeringsdatum.'
  ],
  message: aanvraagValide
    ? 'Aanvraag valide. Route naar gevarenidentificatie gestart.'
    : 'Aanvraag niet valide. Geen Ja gevonden op pagina 3.'
}];

const input = $json || {};
return [{
  ok: true,
  source: 'moc-state-click',
  stateId: input.stateId || null,
  event: input.event || null,
  receivedAt: new Date().toISOString(),
  message: 'Workflowstate-event ontvangen.'
}];

return [{
  ok: true,
  source: 'moc-kpi-sync',
  syncedAt: new Date().toISOString(),
  kpi: {
    openMoc: 7,
    validRequests: 3,
    pendingApprovals: 2,
    evaluationReminders: 1
  },
  message: 'KPI sync uitgevoerd (placeholder data).'
}];

return [{
  source: 'daily-reminder-check',
  runDate: new Date().toISOString(),
  action: 'Controleer dossiers met reminder.dueDate = vandaag en stuur evaluatie-reminder',
  reminderEvent: 'moc.evaluation.reminder.4weeks',
  note: 'Koppel hier opslag (DB/Sheets) en notificatie node (Email/Teams).'
}];
